import { Component, inject, OnInit, ChangeDetectorRef } from '@angular/core';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-profile-settings',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './profile-settings.component.html',
  styles: [`
    .profile-container { max-width: 950px; margin: 0 auto; padding-top: 10px; }
    .profile-card { background: #ffffff; border-radius: 12px; border: 1px solid #e2e8f0; padding: 40px; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05); }
    
    /* En-tête Flex */
    .card-header-flex { display: flex; justify-content: space-between; align-items: center; margin-bottom: 25px; border-bottom: 1px solid #f1f5f9; padding-bottom: 15px; }
    .card-header-left { text-align: left; display: flex; flex-direction: column; gap: 4px; }
    .card-header h3 { margin: 0; color: #0f172a; font-size: 20px; font-weight: 700; display: flex; align-items: center; gap: 10px; }
    .card-header p { margin: 0; color: #64748b; font-size: 14px; }
    
    /* Bouton d'activation d'édition */
    .btn-edit-action { background: #f0f9ff; color: #0ea5e9; border: 1px solid #bae6fd; border-radius: 6px; padding: 8px 16px; font-size: 13,5px; font-weight: 600; cursor: pointer; display: inline-flex; align-items: center; gap: 6px; transition: all 0.2s ease; }
    .btn-edit-action:hover { background: #0ea5e9; color: #ffffff; border-color: #0ea5e9; }

    /* Zone Logo */
    .logo-upload-section { display: flex; align-items: center; gap: 24px; background-color: #f8fafc; padding: 20px; border-radius: 8px; margin-bottom: 25px; border: 1px solid #f1f5f9; }
    .logo-preview { width: 100px; height: 100px; border-radius: 8px; border: 2px solid #e2e8f0; background: #fff; overflow: hidden; display: flex; justify-content: center; align-items: center; box-shadow: 0 1px 2px rgba(0,0,0,0.05); }
    .logo-preview img { width: 100%; height: 100%; object-fit: cover; }
    .btn-secondary-upload { background-color: #ffffff; border: 1px solid #cbd5e1; color: #334155; padding: 8px 16px; border-radius: 6px; font-size: 13px; font-weight: 600; cursor: pointer; display: inline-flex; align-items: center; gap: 6px; transition: all 0.15s ease; }
    .btn-secondary-upload:hover { background: #f8fafc; border-color: #94a3b8; }

    /* Grille et affichages statiques */
    .form-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
    .form-group { display: flex; flex-direction: column; gap: 6px; }
    .form-group label { font-size: 13px; font-weight: 700; color: #64748b; text-align: left; text-transform: uppercase; letter-spacing: 0.5px; }
    .form-group input, .form-group textarea { width: 100%; padding: 10px 14px; border: 1px solid #cbd5e1; border-radius: 6px; font-size: 14px; box-sizing: border-box; font-family: inherit; color: #1e293b; background: #ffffff; }
    .form-group input:focus, .form-group textarea:focus { border-color: #0ea5e9; outline: none; box-shadow: 0 0 0 4px rgba(14, 165, 233, 0.12); }
    
    /* Éléments en lecture seule (Mode consultation) */
    .static-view-text { background: #f8fafc; padding: 11px 14px; border-radius: 6px; border: 1px solid #e2e8f0; font-size: 14px; font-weight: 500; color: #0f172a; text-align: left; min-height: 43px; box-sizing: border-box; }
    .static-view-text.textarea-view { min-height: 120px; line-height: 1.6; white-space: pre-line; }

    .full-width-row { grid-column: span 3; }

    /* Rangée d'actions de soumission */
    .form-actions-row { display: flex; justify-content: flex-end; gap: 12px; margin-top: 30px; border-top: 1px solid #f1f5f9; padding-top: 20px; }
    .btn-cancel { background: #f1f5f9; color: #475569; border: 1px solid #cbd5e1; padding: 11px 22px; font-size: 14px; font-weight: 600; border-radius: 6px; cursor: pointer; }
    .btn-cancel:hover { background: #e2e8f0; }
    .btn-save-submit { background-color: #0ea5e9; color: white; border: none; border-radius: 6px; padding: 11px 24px; font-size: 14px; font-weight: 600; cursor: pointer; display: inline-flex; align-items: center; gap: 8px; }
    .btn-save-submit:hover { background-color: #0284c7; }

    .alert-box { padding: 12px; border-radius: 6px; margin-bottom: 20px; font-size: 14px; text-align: center; font-weight: 600; }
    .alert-success { background-color: #e6f4ea; color: #137333; border: 1px solid #ceead6; }
  `]
})
export class ProfileSettingsComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  profile = { company_name: '', phone: '', email: '', address: '', company_bio: '' };
  backupProfile = { company_name: '', phone: '', email: '', address: '', company_bio: '' };
  logoPreviewUrl: string | null = null;
  selectedFile: File | null = null;
  successMessage = '';
  isEditMode = false;

  // 🚀 VARIABLES POUR LA GESTION DU MOT DE PASSE
  passwordData = { currentPassword: '', newPassword: '', confirmPassword: '' };
  passwordSuccessMessage = '';
  passwordErrorMessage = '';

  ngOnInit() {
    this.loadCurrentProfile();
  }

  toggleEditMode(mode: boolean) {
    this.isEditMode = mode;
    if (mode) {
      // On clone les valeurs au cas où le recruteur clique sur "Annuler"
      this.backupProfile = { ...this.profile };
    } else {
      // Restauration des anciennes valeurs
      this.profile = { ...this.backupProfile };
    }
    this.cdr.detectChanges();
  }

  loadCurrentProfile() {
    const targetUrl = 'http://localhost:3000/api/recruiter/profile/details';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(async res => {
      if (res.ok) return res.json();
      throw new Error();
    })
    .then(data => {
      if (data) {
        this.profile.company_name = data.company_name || localStorage.getItem('name') || '';
        this.profile.phone = data.phone || '';
        this.profile.email = data.email || '';
        this.profile.address = data.address || '';
        this.profile.company_bio = data.company_bio || '';
        
        if (data.company_logo) {
          this.logoPreviewUrl = `http://localhost:3000/uploads/${data.company_logo}`;
        }
        this.cdr.detectChanges();
      }
    })
    .catch(() => {
      this.profile.company_name = localStorage.getItem('name') || '';
      this.cdr.detectChanges();
    });
  }

  onFileSelected(event: any) {
    const file = event.target.files[0];
    if (file) {
      this.selectedFile = file;
      const reader = new FileReader();
      reader.onload = () => {
        this.logoPreviewUrl = reader.result as string;
        this.cdr.detectChanges();
      };
      reader.readAsDataURL(file);

      // 🚀 BONUS : Si le recruteur change la photo, on peut choisir de la sauvegarder directement
      // ou d'attendre qu'il clique sur enregistrer. Ici, elle est prête pour le formulaire global.
    }
  }

  onSaveProfile(event: Event) {
    event.preventDefault();

    const targetUrl = 'http://localhost:3000/api/recruiter/profile/update';
    const token = localStorage.getItem('token');

    const formData = new FormData();
    formData.append('company_name', this.profile.company_name);
    formData.append('phone', this.profile.phone);
    formData.append('email', this.profile.email);
    formData.append('address', this.profile.address);
    formData.append('company_bio', this.profile.company_bio);

    if (this.selectedFile) {
      formData.append('logo', this.selectedFile);
    }

    fetch(targetUrl, {
      method: 'POST',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' },
      body: formData
    })
    .then(async res => {
      if (!res.ok) {
        const errorData = await res.json().catch(() => ({}));
        throw new Error(errorData.message || "Impossible de sauvegarder votre profil.");
      }
      return res.json();
    })
    .then(resData => {
      localStorage.setItem('name', this.profile.company_name);
      this.successMessage = resData.message || "Les informations de votre profil et votre logo ont été mis à jour.";
      this.isEditMode = false; // 🚀 Fermeture du mode édition après succès
      this.cdr.detectChanges();

      setTimeout(() => {
        this.successMessage = '';
        this.cdr.detectChanges();
      }, 3000);
    })
    .catch(err => alert(err.message));
  }
}
<div class="profile-container">
  <div class="profile-card">
    
    <!-- En-tête -->
    <div class="card-header-flex">
      <div class="card-header-left">
        <h3><i class="bi bi-building-fill"></i> Profil de l'entreprise</h3>
        <p>Gérez l'identité de votre marque visible par les candidats en Tunisie.</p>
      </div>
      
      <!-- Bouton d'action principal selon le mode -->
      @if (!isEditMode) {
        <button type="button" class="btn-edit-action" (click)="toggleEditMode(true)">
          <i class="bi bi-pencil-square"></i> Modifier le profil
        </button>
      }
    </div>

    <!-- Message de succès temporisé -->
    @if (successMessage) {
      <div class="alert-box alert-success">
        <i class="bi bi-check-circle-fill"></i> {{ successMessage }}
      </div>
    }

    <!-- SECTION LOGO (INDÉPENDANTE ET INTERACTIVE) -->
    <div class="logo-upload-section">
      <div class="logo-preview">
        @if (logoPreviewUrl) {
          <img [src]="logoPreviewUrl" alt="Logo Entreprise">
        } @else {
          <i class="bi bi-building-fill" style="font-size: 36px; color: #cbd5e1;"></i>
        }
      </div>
      
      <div class="upload-actions">
        <!-- Input binaire masqué pour le traitement d'image -->
        <input 
          type="file" 
          id="logoInput" 
          accept="image/*" 
          (change)="onFileSelected($event)" 
          style="display: none;"
        >
        <button type="button" class="btn-secondary-upload" onclick="document.getElementById('logoInput').click()">
          <i class="bi bi-camera-fill"></i> Modifier la photo de profil
        </button>
        <p style="margin: 6px 0 0 0; font-size: 12px; color: #64748b; text-align: left;">Formats acceptés : JPG, PNG (Max: 2Mo)</p>
      </div>
    </div>

    <!-- FORMULAIRE / AFFICHAGE DES DONNÉES -->
    <form (ngSubmit)="onSaveProfile($event)">
      <div class="form-grid">
        
        <!-- 🏢 Nom de l'entreprise -->
        <div class="form-group">
          <label>Raison sociale (Nom) *</label>
          @if (isEditMode) {
            <input type="text" name="company_name" [(ngModel)]="profile.company_name" required placeholder="Ex: TunJob Tech">
          } @else {
            <div class="static-view-text">{{ profile.company_name || 'Non renseigné' }}</div>
          }
        </div>

        <!-- 📞 Téléphone -->
        <div class="form-group">
          <label>Téléphone de contact *</label>
          @if (isEditMode) {
            <input type="text" name="phone" [(ngModel)]="profile.phone" required placeholder="Ex: +216 71 000 000">
          } @else {
            <div class="static-view-text">{{ profile.phone || 'Non renseigné' }}</div>
          }
        </div>

        <!-- ✉️ Email -->
        <div class="form-group">
          <label>Email de contact *</label>
          @if (isEditMode) {
            <input type="email" name="email" [(ngModel)]="profile.email" required placeholder="Ex: contact@entreprise.tn">
          } @else {
            <div class="static-view-text">{{ profile.email || 'Non renseigné' }}</div>
          }
        </div>

        <!-- 📍 Adresse -->
        <div class="form-group full-width-row">
          <label>Adresse du siège social *</label>
          @if (isEditMode) {
            <input type="text" name="address" [(ngModel)]="profile.address" required placeholder="Ex: Les Berges du Lac 2, Tunis, Tunisie">
          } @else {
            <div class="static-view-text">{{ profile.address || 'Non renseigné' }}</div>
          }
        </div>

        <!-- 📝 Présentation -->
        <div class="form-group full-width-row">
          <label>Présentation de l'entreprise & Activités *</label>
          @if (isEditMode) {
            <textarea name="company_bio" [(ngModel)]="profile.company_bio" rows="5" required placeholder="Décrivez votre histoire..."></textarea>
          } @else {
            <div class="static-view-text textarea-view">{{ profile.company_bio || 'Aucune description disponible pour le moment.' }}</div>
          }
        </div>
      </div>

      <!-- Actions de validation en mode édition uniquement -->
      @if (isEditMode) {
        <div class="form-actions-row">
          <button type="button" class="btn-cancel" (click)="toggleEditMode(false)">
            Annuler
          </button>
          <button type="submit" class="btn-save-submit">
            <i class="bi bi-shield-check"></i> Enregistrer les modifications
          </button>
        </div>
      }
    </form>

  </div>
      <!-- 🔐 NOUVELLE SECTION : SÉCURITÉ & MOT DE PASSE -->
    <div class="security-section-divider"></div>
    
    <div class="card-header" style="margin-top: 20px;">
      <h3><i class="bi bi-shield-lock-fill"></i> Sécurité du compte</h3>
      <p>Modifiez votre mot de passe pour sécuriser l'accès à votre espace recruteur.</p>
    </div>

    <!-- Message de notification spécifique pour le mot de passe -->
    @if (passwordSuccessMessage) {
      <div class="alert-box alert-success" style="margin-bottom: 20px;">
        <i class="bi bi-check-circle-fill"></i> {{ passwordSuccessMessage }}
      </div>
    }
    @if (passwordErrorMessage) {
      <div class="alert-box alert-danger" style="margin-bottom: 20px; background-color: #fef2f2; color: #991b1b; border: 1px solid #fee2e2;">
        <i class="bi bi-exclamation-triangle-fill"></i> {{ passwordErrorMessage }}
      </div>
    }

    <form (ngSubmit)="onUpdatePassword($event)">
      <div class="form-grid">
        <!-- Champ 1 : Ancien Mot de passe -->
        <div class="form-group">
          <label for="current_password">Mot de passe actuel *</label>
          <input type="password" id="current_password" name="current_password" [(ngModel)]="passwordData.currentPassword" required placeholder="••••••••">
        </div>

        <!-- Champ 2 : Nouveau Mot de passe -->
        <div class="form-group">
          <label for="new_password">Nouveau mot de passe *</label>
          <input type="password" id="new_password" name="new_password" [(ngModel)]="passwordData.newPassword" required placeholder="Minimum 6 caractères">
        </div>

        <!-- Champ 3 : Confirmation -->
        <div class="form-group">
          <label for="confirm_password">Confirmer le nouveau mot de passe *</label>
          <input type="password" id="confirm_password" name="confirm_password" [(ngModel)]="passwordData.confirmPassword" required placeholder="••••••••">
        </div>
      </div>

      <button type="submit" class="btn-save" style="background-color: #0f172a !important; margin-top: 20px;">
        <i class="bi bi-key-fill"></i> Mettre à jour le mot de passe
      </button>
    </form>

</div>
